  // Forward the request to your backend service
  const backendUrl = 'https://your-backend-service.com'; // Replace with your actual backend URL
  const backendRequest = new Request(request.url.replace('http://your-worker-url', backendUrl), request);

  try {
    const response = await fetch(backendRequest);
    return new Response(response.body, {
      ...response,
      headers: new Headers([...response.headers.entries(), ...Object.entries(corsHeaders)])
    });
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Internal Server Error' }), {
      status: 500,
      headers: corsHeaders
    });
  }
